function normSourceUrl(raw) {
  if (!raw) return null;
  try {
    const u = new URL(String(raw).trim());
    const host = (u.hostname || '').toLowerCase().replace(/^www\./, '');
    const agg = ['jobwebzambia.com','gozambiajobs.com','jobsearchzambia.com','jobsearchzm.com'];
    const path = (u.pathname || '/').replace(/\/+$/, '') || '/';
    const pathOnly = path === '/' ? '' : path.replace(/^\//, '');
    const seg = pathOnly.split('/').filter(Boolean);
    if (agg.some(d => host === d || host.endsWith('.' + d))) {
      if (!seg.length || (seg.length === 1 && ['jobs','job','vacancies','careers'].includes(seg[0].toLowerCase()))) return null;
    }
    return String(raw).trim().substring(0, 2000);
  } catch { return null; }
}

function normPostedAt(raw) {
  if (!raw) return null;
  const s = String(raw).trim();
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.substring(0, 10);
  const parsed = Date.parse(s);
  if (!Number.isNaN(parsed)) return new Date(parsed).toISOString().substring(0, 10);
  const rel = s.match(/^(\d+)\s*(h|hour|hr|d|day|w|week|m|month)s?\s+ago$/i);
  if (rel) {
    const n = parseInt(rel[1], 10);
    const u = rel[2].toLowerCase()[0];
    const d = new Date();
    if (u === 'h') d.setHours(d.getHours() - n);
    else if (u === 'd') d.setDate(d.getDate() - n);
    else if (u === 'w') d.setDate(d.getDate() - n * 7);
    else if (u === 'm') d.setMonth(d.getMonth() - n);
    return d.toISOString().substring(0, 10);
  }
  return null;
}

function slugify(t) {
  return String(t || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

function matchLinkForJob(job, links) {
  if (!links || !links.length) return null;
  const titleSlug = slugify(job.title);
  const words = titleSlug.split('-').filter(w => w.length > 3);
  let best = null;
  let bestScore = 0;
  for (const url of links) {
    const path = url.toLowerCase();
    let score = 0;
    if (titleSlug.length > 8 && path.includes(titleSlug.slice(0, 48))) score += 12;
    for (const w of words) {
      if (path.includes(w)) score += 2;
    }
    if (score > bestScore) {
      bestScore = score;
      best = url;
    }
  }
  return bestScore >= 3 ? best : null;
}

function parseJobsPayload(item) {
  if (item.json.error) return null;
  if (item.json.jobs && Array.isArray(item.json.jobs)) return item.json;
  let text = null;
  if (item.json.choices?.[0]?.message?.content) {
    text = item.json.choices[0].message.content;
  } else if (item.json.candidates?.[0]) {
    text = item.json.candidates[0].content.parts[0].text;
  } else if (item.json.text) {
    text = typeof item.json.text === 'string' ? item.json.text : JSON.stringify(item.json.text);
  }
  if (text) {
    const m = text.match(/\{[\s\S]*"jobs"[\s\S]*\}/);
    if (m) return JSON.parse(m[0]);
  }
  const blob = JSON.stringify(item.json);
  const m = blob.match(/\{[\s\S]*"jobs"[\s\S]*\}/);
  if (m) return JSON.parse(m[0]);
  return null;
}

const prepNames = [
  'Prep GoZambia Body',
  'Prep JobWebZambia Body',
  'Prep LinkedIn Body',
  'Prep JobSearchZM Body',
];

function linksForBranch(index) {
  try {
    const prep = $(prepNames[index]).first();
    const links = prep?.json?.extractedLinks;
    return Array.isArray(links) ? links : [];
  } catch {
    return [];
  }
}

const allJobs = [];
const seen = new Set();
const inputs = $input.all();

for (let branch = 0; branch < inputs.length; branch++) {
  const item = inputs[branch];
  const linkPool = linksForBranch(branch);
  let data;
  try {
    data = parseJobsPayload(item);
  } catch {
    continue;
  }
  if (!data?.jobs) continue;

  for (const j of data.jobs) {
    if (!j.title) continue;
    const hasRef = j.apply_url || j.apply_email;
    const descRaw = (j.description || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    if (descRaw.length < 10 && !hasRef) continue;

    let sourceUrl = normSourceUrl(j.source_url || j.apply_url);
    if (!sourceUrl) {
      const guessed = matchLinkForJob(j, linkPool);
      if (guessed) sourceUrl = normSourceUrl(guessed);
    }

    const description = descRaw.length >= 10
      ? descRaw.substring(0, 5000)
      : (j.title + (j.company ? ' at ' + j.company : '') + (j.location ? ' in ' + j.location : '') + '.');

    const k = (j.title + '|' + (j.company || '')).toLowerCase().trim();
    if (seen.has(k)) continue;
    seen.add(k);

    allJobs.push({
      title: (j.title || '').trim().substring(0, 200),
      company: (j.company || '').trim().substring(0, 200) || null,
      location: (j.location || '').trim() || null,
      description,
      requirements: Array.isArray(j.requirements) ? j.requirements : [],
      skills_required: Array.isArray(j.skills_required) ? j.skills_required : [],
      salary_min: j.salary_min || null,
      salary_max: j.salary_max || null,
      apply_url: j.apply_url || null,
      apply_email: j.apply_email || null,
      source: 'scraper',
      source_url: sourceUrl,
      closing_date: j.closing_date || null,
      posted_at: normPostedAt(j.posted_at),
    });
  }
}

return [{ json: { jobs: allJobs, count: allJobs.length } }];
